using namespace std;
vector<int> mergeSorted(vector<int>&a,vector<int>&b){
    vector<int> res; int i=0,j=0;
    while(i<(int)a.size()&&j<(int)b.size()){if(a[i]<=b[j])res.push_back(a[i++]);else res.push_back(b[j++]);}
